private void xrTableCell180_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    var femalesTrans = Convert.ToDecimal(GetCurrentColumnValue("FemalesTrans"));
    var femalesDepleted = Convert.ToDecimal(GetCurrentColumnValue("FemalesDepleted"));

    if (femalesTrans != 0)
        ((XRTableCell)sender).Text = ((femalesDepleted / femalesTrans) * 100).ToString("N2");
    else
        ((XRTableCell)sender).Text = "0";
}

private void xrTableCell38_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal htRejDeformed = 0;
decimal stRejDeformed = 0;

// --- Read values ---
if (GetCurrentColumnValue("HT_RejDeformed") != null && 
    !string.IsNullOrEmpty(GetCurrentColumnValue("HT_RejDeformed").ToString()))
{
    htRejDeformed = Convert.ToDecimal(GetCurrentColumnValue("HT_RejDeformed"));
}

if (GetCurrentColumnValue("ST_RejDeformed") != null && 
    !string.IsNullOrEmpty(GetCurrentColumnValue("ST_RejDeformed").ToString()))
{
    stRejDeformed = Convert.ToDecimal(GetCurrentColumnValue("ST_RejDeformed"));
}

// --- Equation ---
decimal result = htRejDeformed + stRejDeformed;


// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("0.##");   // format with 2 decimals

}

