private void xrTableCell47_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal rejBroken = 0;
decimal rejCrack = 0;
decimal rejDef = 0;
decimal rejOther = 0;

// --- Read values safely ---
if (GetCurrentColumnValue("RejBroken") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("RejBroken").ToString()) &&
    Convert.ToDecimal(GetCurrentColumnValue("RejBroken")) != 0)
{
    rejBroken = Convert.ToDecimal(GetCurrentColumnValue("RejBroken"));
}

if (GetCurrentColumnValue("RejCrack") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("RejCrack").ToString()) &&
    Convert.ToDecimal(GetCurrentColumnValue("RejCrack")) != 0)
{
    rejCrack = Convert.ToDecimal(GetCurrentColumnValue("RejCrack"));
}

if (GetCurrentColumnValue("RejDef") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("RejDef").ToString()) &&
    Convert.ToDecimal(GetCurrentColumnValue("RejDef")) != 0)
{
    rejDef = Convert.ToDecimal(GetCurrentColumnValue("RejDef"));
}

if (GetCurrentColumnValue("RejOther") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("RejOther").ToString()) &&
    Convert.ToDecimal(GetCurrentColumnValue("RejOther")) != 0)
{
    rejOther = Convert.ToDecimal(GetCurrentColumnValue("RejOther"));
}

// --- Equation ---
decimal result = rejBroken + rejCrack + rejDef + rejOther;

// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("0.##");   // format with 2 decimals

}

private void xrTableCell49_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal farmInTake = 0;
decimal rejBroken = 0;
decimal rejCrack = 0;
decimal rejDef = 0;
decimal rejOther = 0;

// --- Read values safely ---
if (GetCurrentColumnValue("FarmInTake") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("FarmInTake").ToString()))
{
    farmInTake = Convert.ToDecimal(GetCurrentColumnValue("FarmInTake"));
}

if (GetCurrentColumnValue("RejBroken") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("RejBroken").ToString()) &&
    Convert.ToDecimal(GetCurrentColumnValue("RejBroken")) != 0)
{
    rejBroken = Convert.ToDecimal(GetCurrentColumnValue("RejBroken"));
}

if (GetCurrentColumnValue("RejCrack") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("RejCrack").ToString()) &&
    Convert.ToDecimal(GetCurrentColumnValue("RejCrack")) != 0)
{
    rejCrack = Convert.ToDecimal(GetCurrentColumnValue("RejCrack"));
}

if (GetCurrentColumnValue("RejDef") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("RejDef").ToString()) &&
    Convert.ToDecimal(GetCurrentColumnValue("RejDef")) != 0)
{
    rejDef = Convert.ToDecimal(GetCurrentColumnValue("RejDef"));
}

if (GetCurrentColumnValue("RejOther") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("RejOther").ToString()) &&
    Convert.ToDecimal(GetCurrentColumnValue("RejOther")) != 0)
{
    rejOther = Convert.ToDecimal(GetCurrentColumnValue("RejOther"));
}

// --- Equation ---
decimal totalRej = rejBroken + rejCrack + rejDef + rejOther;
decimal result = farmInTake - totalRej;

// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("0.##");   // format with 2 decimals

}

private void xrTableCell55_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
// --- Declare values ---
decimal selChicks = 0;
decimal cullsChicks = 0;
decimal deadChicks = 0;

// --- Read values safely ---
if (GetCurrentColumnValue("SelChicks") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("SelChicks").ToString()) &&
    Convert.ToDecimal(GetCurrentColumnValue("SelChicks")) != 0)
{
    selChicks = Convert.ToDecimal(GetCurrentColumnValue("SelChicks"));
}

if (GetCurrentColumnValue("CullsChicks") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("CullsChicks").ToString()) &&
    Convert.ToDecimal(GetCurrentColumnValue("CullsChicks")) != 0)
{
    cullsChicks = Convert.ToDecimal(GetCurrentColumnValue("CullsChicks"));
}

if (GetCurrentColumnValue("DeadChicks") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("DeadChicks").ToString()) &&
    Convert.ToDecimal(GetCurrentColumnValue("DeadChicks")) != 0)
{
    deadChicks = Convert.ToDecimal(GetCurrentColumnValue("DeadChicks"));
}

// --- Equation ---
decimal totalChicks = selChicks + cullsChicks + deadChicks;


// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = totalChicks.ToString("0.##");   // format with 2 decimals

}
